class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int val) { this.val = val; }
}

class Result {
    int min;
    int max;
}

int dfs(TreeNode node, Result result) {
    if (node == null) return 0;
    Result leftResult = new Result();
    Result rightResult = new Result();
    int leftDiff = dfs(node.left, leftResult);
    int rightDiff = dfs(node.right, rightResult);
    result.min = Math.min(node.val, Math.min(leftResult.min, rightResult.min));
    result.max = Math.max(node.val, Math.max(leftResult.max, rightResult.max));
    return Math.max(Math.max(leftDiff, rightDiff), Math.max(Math.abs(node.val - leftResult.min), Math.abs(node.val - rightResult.max)));
}

int maxAncestorDiff(TreeNode root) {
    Result result = new Result();
    return dfs(root, result);
}
